/**
 * @summary Get a redirect URL to view a document at a specific page
 */
export const getGetDocumentViewUrlUrl = (
  id: string,
  params?: GetDocumentViewUrlParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/documents/${id}/view?${stringifiedParams}`
    : `/api/documents/${id}/view`;
};

export const getDocumentViewUrl = async (
  id: string,
  params?: GetDocumentViewUrlParams,
  options?: RequestInit,
): Promise<unknown> => {
  return customFetch<unknown>(getGetDocumentViewUrlUrl(id, params), {
    ...options,
    method: "GET",
  });
};

export const getGetDocumentViewUrlQueryKey = (
  id: string,
  params?: GetDocumentViewUrlParams,
) => {
  return [`/api/documents/${id}/view`, ...(params ? [params] : [])] as const;
};

export const getGetDocumentViewUrlQueryOptions = <
  TData = Awaited<ReturnType<typeof getDocumentViewUrl>>,
  TError = ErrorType<void | ErrorResponse>,
>(
  id: string,
  params?: GetDocumentViewUrlParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof getDocumentViewUrl>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey =
    queryOptions?.queryKey ?? getGetDocumentViewUrlQueryKey(id, params);

  const queryFn: QueryFunction<
    Awaited<ReturnType<typeof getDocumentViewUrl>>
  > = ({ signal }) =>
    getDocumentViewUrl(id, params, { signal, ...requestOptions });

  return {
    queryKey,
    queryFn,
    enabled: !!id,
    ...queryOptions,
  } as UseQueryOptions<
    Awaited<ReturnType<typeof getDocumentViewUrl>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

